    private WebServiceContext wsContext;
    
    private static final PaymentProcessor paymentProcessor = new PaymentProcessor();
    
    @WebMethod
    public PaymentResponse processPayment(
            @WebParam(name = "cardNumber") String cardNumber,
            @WebParam(name = "cardHolderName") String cardHolderName,
            @WebParam(name = "expiryDate") String expiryDate,
            @WebParam(name = "cvv") String cvv,
            @WebParam(name = "amount") double amount,
            @WebParam(name = "currency") String currency) {
        
        try {
            LOGGER.info("Processing payment request");
            
            if (!validateInput(cardNumber, cardHolderName, expiryDate, cvv, amount, currency)) {
                return new PaymentResponse(false, "Invalid input parameters", null);
            }
            
            String maskedCardNumber = maskCardNumber(cardNumber);
            
            String transactionId = paymentProcessor.processTransaction(
                cardNumber, cardHolderName, expiryDate, cvv, amount, currency);
            
            LOGGER.info("Payment processed successfully. Transaction ID: " + transactionId);
            
            return new PaymentResponse(true, "Payment processed successfully", transactionId);
            
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing payment", e);
            return new PaymentResponse(false, "Payment processing failed", null);
        }
    }
    
    @WebMethod
    public PaymentStatusResponse getPaymentStatus(@WebParam(name = "transactionId") String transactionId) {
        try {
            if (transactionId == null || transactionId.trim().isEmpty()) {
                return new PaymentStatusResponse(false, "Invalid transaction ID", null);
            }
            
            String status = paymentProcessor.getTransactionStatus(transactionId);
            
            if (status == null) {
                return new PaymentStatusResponse(false, "Transaction not found", null);
            }
            
            return new PaymentStatusResponse(true, "Status retrieved", status);
            
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error retrieving payment status", e);
            return new PaymentStatusResponse(false, "Error retrieving status", null);
        }
    }
    
    private boolean validateInput(String cardNumber, String cardHolderName, 
                                  String expiryDate, String cvv, double amount, String currency) {
        if (cardNumber == null || !cardNumber.matches("\\d{13,19}")) {
            return false;
        }
        
        if (cardHolderName == null || cardHolderName.trim().isEmpty() || 
            cardHolderName.length() > 100) {
            return false;
        }
        
        if (expiryDate == null || !expiryDate.matches("\\d{2}/\\d{2}")) {
            return false;
        }
        
        if (cvv == null || !cvv.matches("\\d{3,4}")) {
            return false;
        }
        
        if (amount <= 0 || amount > 1000000) {
            return false;
        }
        
        if (currency == null || !currency.matches("[A-Z]{3}")) {
            return false;
        }
        
        return true;
    }
    
    private String maskCardNumber(String cardNumber) {
        if (cardNumber == null || cardNumber.length() < 4) {
            return "****";
        }
        return "****" + cardNumber.substring(cardNumber.length() - 4);
    }
