class PaymentProcessor {
    private static final Logger LOGGER = Logger.getLogger(PaymentProcessor.class.getName());
    private final Map<String, TransactionRecord> transactions = new ConcurrentHashMap<>();
    private final SecureRandom secureRandom = new SecureRandom();
    
    public String processTransaction(String cardNumber, String cardHolderName, 
                                     String expiryDate, String cvv, 
                                     double amount, String currency) {
        String transactionId = generateTransactionId();
        
        TransactionRecord record = new TransactionRecord(
            transactionId, amount, currency, "COMPLETED", Instant.now());
        
        transactions.put(transactionId, record);
        
        LOGGER.info("Transaction created: " + transactionId);
        
        return transactionId;
    }
    
    public String getTransactionStatus(String transactionId) {
        TransactionRecord record = transactions.get(transactionId);
        return record != null ? record.getStatus() : null;
    }
    
    private String generateTransactionId() {
        byte[] randomBytes = new byte[16];
        secureRandom.nextBytes(randomBytes);
        
        StringBuilder sb = new StringBuilder();
        for (byte b : randomBytes) {
            sb.append(String.format("%02x", b));
        }
        
        return "TXN-" + sb.toString().toUpperCase();
    }
}

